function ProductCard({ product, currency, ps, onAdd, delay = 0 }) {
  const [hover, setHover] = useState(false);
  const hasDiscount = product.oldPrice && product.oldPrice > product.salePrice;
  const discount = hasDiscount ? Math.round((1 - product.salePrice / product.oldPrice) * 100) : 0;
  const stock = ps?.remaining || 0;
  const rate = currency === 'AED' ? 1 : (1 / SEED_SETTINGS.fxRates[currency]);
  const displayPrice = Math.round(product.salePrice * rate);
  const displayOld = product.oldPrice ? Math.round(product.oldPrice * rate) : null;

  return (
    <article
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      style={{ background: T.bg, animation: `fadeUp 600ms ease-out ${delay}ms both` }}
    >
      <div style={{
        position: 'relative', aspectRatio: '4/5',
        background: T.bg,
        border: `1px solid ${hover ? T.goldDecor : T.borderLight}`,
        overflow: 'hidden', marginBottom: 18,
        transition: 'border-color 250ms ease',
      }}>
        <div style={{
          position: 'absolute', inset: 12,
          border: `1px solid ${T.goldDecor}30`,
          pointerEvents: 'none',
        }} />
        <div style={{
          position: 'absolute', top: '50%', left: '50%',
          transform: `translate(-50%, -50%) ${hover ? 'scale(1.05)' : 'scale(1)'}`,
          transition: 'transform 400ms ease',
          width: '55%', opacity: 0.18,
        }}>
          <img src={LOGO} alt="" style={{ width: '100%', display: 'block' }} />
        </div>
        <div style={{
          position: 'absolute', top: 12, left: 12,
          padding: '4px 8px', background: T.bg,
          border: `1px solid ${T.borderLight}`,
          fontSize: 9, color: T.faint, letterSpacing: 0.5,
        }}>صورة المنتج</div>

        <div style={{
          position: 'absolute', top: 14, right: 14,
          display: 'flex', flexDirection: 'column',
          gap: 6, alignItems: 'flex-end',
        }}>
          <span className="mono" style={{
            padding: '4px 10px', background: T.bg,
            border: `1px solid ${T.goldDecor}`,
            color: T.goldDeep, fontSize: 10, fontWeight: 700, letterSpacing: 1,
          }}>{product.grade}</span>
          {hasDiscount && (
            <span style={{
              padding: '4px 10px', background: T.red, color: '#fff',
              fontSize: 10, fontWeight: 700, letterSpacing: 0.5,
            }}>-{discount}%</span>
          )}
          {stock < 5 && stock > 0 && !hasDiscount && (
            <span style={{
              padding: '4px 10px', background: T.red, color: '#fff',
              fontSize: 10, fontWeight: 700,
            }}>متبقي {Math.floor(stock)}</span>
          )}
          {stock <= 0 && (
            <span style={{
              padding: '4px 10px', background: T.ink, color: '#fff',
              fontSize: 10, fontWeight: 700,
            }}>نفذ</span>
          )}
        </div>

        <div style={{
          position: 'absolute', bottom: 0, left: 0, right: 0,
          padding: 12,
          display: 'flex', gap: 8,
          opacity: hover ? 1 : 0,
          transform: hover ? 'translateY(0)' : 'translateY(8px)',
          transition: 'all 250ms ease',
        }}>
          <button onClick={onAdd} disabled={stock <= 0} style={{
            flex: 1, padding: '12px',
            background: stock <= 0 ? T.faint : T.ink, color: '#fff',
            fontSize: 11, fontWeight: 700, letterSpacing: 1.5,
            minHeight: 44, cursor: stock <= 0 ? 'not-allowed' : 'pointer',
          }}
          onMouseEnter={e => { if (stock > 0) e.currentTarget.style.background = T.goldUI; }}
          onMouseLeave={e => { if (stock > 0) e.currentTarget.style.background = T.ink; }}
          >{stock <= 0 ? 'نفذ' : 'أضف للسلة'}</button>
          <button style={{
            width: 44, height: 44, background: T.bg,
            border: `1px solid ${T.borderLight}`,
            display: 'grid', placeItems: 'center', color: T.ink,
          }} aria-label="مفضلة">
            <Heart size={16} strokeWidth={1.5} />
          </button>
        </div>
      </div>

      <div style={{ padding: '0 4px' }}>
        <div className="latin-display" style={{
          fontSize: 10, color: T.faint, letterSpacing: 2.5,
          marginBottom: 6, fontWeight: 500, fontStyle: 'italic',
        }}>{product.origin}</div>
        <h3 className="arabic-display" style={{
          fontSize: 19, fontWeight: 500, color: T.ink, marginBottom: 4,
        }}>{product.name}</h3>
        <div className="latin-display" style={{
          fontSize: 13, color: T.muted,
          fontStyle: 'italic', marginBottom: 14,
        }}>{product.type}</div>
        <div style={{ display: 'flex', alignItems: 'baseline', gap: 10 }}>
          <span className="mono" style={{ fontSize: 18, fontWeight: 600, color: T.ink }}>
            {displayPrice.toLocaleString('ar-AE')}
            <span style={{ fontSize: 11, color: T.muted, marginRight: 4, fontWeight: 500 }}>{currency}</span>
          </span>
          {displayOld && (
            <span className="mono" style={{
              fontSize: 13, color: T.faint, textDecoration: 'line-through',
            }}>{displayOld.toLocaleString('ar-AE')}</span>
          )}
        </div>
      </div>
    </article>
  );
}

