// ═══════════════════════════════════════════════════════════════════════
// CART PAGE — places real orders into ERP
// ═══════════════════════════════════════════════════════════════════════
function CartPage({ cart, setCart, currency, products, settings, onCheckout }) {
  const [customer, setCustomer] = useState({ name: '', city: '' });
  const total = cart.reduce((s, item) => s + (item.salePrice || 0) * (item.qty || 1), 0);

  const updateQty = (idx, qty) => {
    if (qty <= 0) {
      setCart(cart.filter((_, i) => i !== idx));
    } else {
      setCart(cart.map((item, i) => i === idx ? { ...item, qty } : item));
    }
  };

  if (cart.length === 0) {
    return (
      <main style={{ padding: '80px 32px', minHeight: '60vh', background: T.bg }}>
        <div style={{ maxWidth: 600, margin: '0 auto', textAlign: 'center' }}>
          <ShoppingBag size={48} style={{ color: T.faint, margin: '0 auto 24px' }} strokeWidth={1} />
          <h1 className="arabic-display" style={{ fontSize: 36, fontWeight: 500, color: T.ink, marginBottom: 16 }}>
            سلتك فارغة
          </h1>
          <p style={{ color: T.muted, fontSize: 15 }}>أضف منتجات للمتابعة</p>
        </div>
      </main>
    );
  }

  return (
    <main style={{ padding: '60px 32px', minHeight: '60vh', background: T.bg }}>
      <div style={{ maxWidth: 1100, margin: '0 auto' }}>
        <h1 className="arabic-display" style={{ fontSize: 36, fontWeight: 500, color: T.ink, marginBottom: 8 }}>
          سلة المشتريات
        </h1>
        <p style={{ color: T.muted, fontSize: 14, marginBottom: 40 }}>{cart.length} منتجات</p>

        <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: 40 }}>
          <div>
            {cart.map((item, idx) => (
              <div key={idx} style={{
                display: 'grid', gridTemplateColumns: 'auto 1fr auto auto',
                gap: 20, alignItems: 'center',
                padding: '20px 0',
                borderBottom: `1px solid ${T.borderLight}`,
              }}>
                <div style={{
                  width: 80, height: 80,
                  background: T.paper,
                  border: `1px solid ${T.borderLight}`,
                  display: 'grid', placeItems: 'center',
                }}>
                  <img src={LOGO} alt="" style={{ width: '60%', opacity: 0.3 }} />
                </div>
                <div>
                  <div className="arabic-display" style={{ fontSize: 16, fontWeight: 600, color: T.ink, marginBottom: 4 }}>
                    {item.name}
                  </div>
                  <div style={{ fontSize: 12, color: T.muted }}>{item.origin} · {item.grade}</div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8, border: `1px solid ${T.borderLight}` }}>
                  <button onClick={() => updateQty(idx, (item.qty || 1) - 1)} style={{ width: 32, height: 32, color: T.ink }}>
                    −
                  </button>
                  <span className="mono" style={{ minWidth: 24, textAlign: 'center', fontWeight: 600 }}>{item.qty || 1}</span>
                  <button onClick={() => updateQty(idx, (item.qty || 1) + 1)} style={{ width: 32, height: 32, color: T.ink }}>
                    +
                  </button>
                </div>
                <div className="mono" style={{ fontSize: 16, fontWeight: 600, color: T.ink, minWidth: 100, textAlign: 'left' }}>
                  {((item.salePrice || 0) * (item.qty || 1)).toLocaleString('ar-AE')}
                  <span style={{ fontSize: 11, color: T.muted, marginRight: 4 }}>د.إ</span>
                </div>
              </div>
            ))}
          </div>

          <div style={{ background: T.paper, padding: 24, border: `1px solid ${T.borderLight}`, height: 'fit-content' }}>
            <h3 className="arabic-display" style={{ fontSize: 18, fontWeight: 500, color: T.ink, marginBottom: 20 }}>
              ملخص الطلب
            </h3>
            <div style={{ marginBottom: 24, display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: T.muted, letterSpacing: 1, marginBottom: 6 }}>
                  الاسم
                </label>
                <input
                  value={customer.name}
                  onChange={e => setCustomer({ ...customer, name: e.target.value })}
                  placeholder="الاسم الكامل"
                  style={{
                    width: '100%', padding: '10px 12px',
                    background: T.bg, border: `1px solid ${T.borderLight}`,
                    outline: 'none', fontSize: 13,
                  }}
                />
              </div>
              <div>
                <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: T.muted, letterSpacing: 1, marginBottom: 6 }}>
                  المدينة
                </label>
                <input
                  value={customer.city}
                  onChange={e => setCustomer({ ...customer, city: e.target.value })}
                  placeholder="دبي / الرياض / ..."
                  style={{
                    width: '100%', padding: '10px 12px',
                    background: T.bg, border: `1px solid ${T.borderLight}`,
                    outline: 'none', fontSize: 13,
                  }}
                />
              </div>
            </div>
            <div style={{ borderTop: `1px solid ${T.borderLight}`, paddingTop: 16, marginBottom: 24 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
                <span style={{ fontSize: 13, color: T.muted }}>المجموع</span>
                <span className="mono" style={{ fontSize: 13, color: T.ink }}>{total.toLocaleString('ar-AE')} د.إ</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
                <span style={{ fontSize: 13, color: T.muted }}>الشحن</span>
                <span style={{ fontSize: 13, color: T.green, fontWeight: 600 }}>مجاني</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', paddingTop: 12, borderTop: `1px solid ${T.borderLight}` }}>
                <span style={{ fontSize: 15, fontWeight: 700, color: T.ink }}>الإجمالي</span>
                <span className="mono" style={{ fontSize: 20, fontWeight: 700, color: T.goldUI }}>
                  {total.toLocaleString('ar-AE')} <span style={{ fontSize: 12, color: T.muted }}>د.إ</span>
                </span>
              </div>
            </div>
            <button
              onClick={() => {
                if (!customer.name || !customer.city) return;
                onCheckout(customer);
              }}
              disabled={!customer.name || !customer.city}
              style={{
                width: '100%', padding: '14px',
                background: (!customer.name || !customer.city) ? T.faint : T.ink,
                color: '#fff', fontSize: 12, fontWeight: 700,
                letterSpacing: 2, minHeight: 48,
                cursor: (!customer.name || !customer.city) ? 'not-allowed' : 'pointer',
              }}
              onMouseEnter={e => { if (customer.name && customer.city) e.currentTarget.style.background = T.goldUI; }}
              onMouseLeave={e => { if (customer.name && customer.city) e.currentTarget.style.background = T.ink; }}
            >
              تأكيد الطلب
            </button>
          </div>
        </div>
      </div>
    </main>
  );
}

