function Login({ onSuccess, onBack }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);

  return (
    <div style={{
      minHeight: '100vh', background: T.bg,
      display: 'grid', placeItems: 'center',
      padding: '40px 24px', position: 'relative',
    }}>
      <button onClick={onBack} style={{
        position: 'absolute', top: 24, right: 32,
        fontSize: 12, color: T.faint,
        padding: '8px 12px',
        display: 'flex', alignItems: 'center', gap: 6,
      }}>
        <ArrowRight size={14} />
        رجوع للمتجر
      </button>

      <div style={{ width: '100%', maxWidth: 380 }}>
        <div style={{ textAlign: 'center', marginBottom: 36 }}>
          <img src={LOGO} alt="" style={{ width: 84, height: 84, objectFit: 'contain', display: 'block', margin: '0 auto' }} />
        </div>
        <div style={{ background: T.bg, border: `1px solid ${T.borderLight}`, padding: '40px 36px' }}>
          <div style={{ textAlign: 'center', marginBottom: 32 }}>
            <Lock size={18} style={{ color: T.goldUI, margin: '0 auto 14px' }} strokeWidth={1.3} />
            <div className="latin-display" style={{
              fontSize: 11, color: T.goldDeep, letterSpacing: 4,
              fontWeight: 500, marginBottom: 6, fontStyle: 'italic',
            }}>Secure Admin Access</div>
            <div style={{ fontSize: 13, color: T.muted }}>تسجيل دخول الإدارة</div>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
            <div>
              <label style={{ display: 'block', fontSize: 10, fontWeight: 700, color: T.muted, letterSpacing: 1.5, marginBottom: 8 }}>
                USERNAME
              </label>
              <input
                value={username} onChange={e => setUsername(e.target.value)}
                placeholder="admin"
                style={{
                  width: '100%', padding: '13px 14px', fontSize: 14,
                  background: T.bg, border: `1px solid ${T.borderLight}`,
                  outline: 'none', minHeight: 46, color: T.ink,
                }}
              />
            </div>
            <div>
              <label style={{ display: 'block', fontSize: 10, fontWeight: 700, color: T.muted, letterSpacing: 1.5, marginBottom: 8 }}>
                PASSWORD
              </label>
              <div style={{ position: 'relative' }}>
                <input
                  type={showPass ? 'text' : 'password'}
                  value={password} onChange={e => setPassword(e.target.value)}
                  placeholder="••••••••"
                  style={{
                    width: '100%', padding: '13px 44px 13px 14px',
                    fontSize: 14, background: T.bg,
                    border: `1px solid ${T.borderLight}`,
                    outline: 'none', minHeight: 46, color: T.ink,
                  }}
                />
                <button onClick={() => setShowPass(!showPass)} style={{
                  position: 'absolute', left: 8, top: '50%',
                  transform: 'translateY(-50%)',
                  width: 32, height: 32,
                  display: 'grid', placeItems: 'center', color: T.muted,
                }}>
                  {showPass ? <EyeOff size={15} /> : <Eye size={15} />}
                </button>
              </div>
            </div>
            <button onClick={onSuccess} style={{
              marginTop: 12, padding: '14px',
              background: T.ink, color: '#fff',
              fontSize: 12, fontWeight: 700, letterSpacing: 2,
              minHeight: 48,
            }}
            onMouseEnter={e => e.currentTarget.style.background = T.goldUI}
            onMouseLeave={e => e.currentTarget.style.background = T.ink}
            >تسجيل الدخول</button>
            <div style={{
              textAlign: 'center', paddingTop: 18, marginTop: 4,
              borderTop: `1px solid ${T.borderLight}`,
            }}>
              <div style={{
                display: 'inline-flex', alignItems: 'center', gap: 6,
                fontSize: 10, color: T.faint, letterSpacing: 1.5, fontWeight: 600,
              }}>
                <Shield size={11} />
                CONNECTION SECURE · SSL/TLS
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

