function Admin({ tab, setTab, data, settings, stats, openSheet, deleteItem, onShowSettings, onShowLogs, onShowBackup, onLogout, onPrintOrder }) {
  const fabAction = () => {
    if (tab === 'home' || tab === 'orders') openSheet({ type: 'order' });
    else if (tab === 'inventory') openSheet({ type: 'product' });
    else if (tab === 'suppliers') openSheet({ type: 'supplier' });
    else if (tab === 'expenses') openSheet({ type: 'expense' });
    else openSheet({ type: 'order' });
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: T.bg }}>
      <AdminSidebar
        tab={tab} setTab={setTab}
        onShowSettings={onShowSettings}
        onShowLogs={onShowLogs}
        onShowBackup={onShowBackup}
        onLogout={onLogout}
      />
      <main style={{ flex: 1, padding: '32px 40px', overflow: 'auto', background: T.paper, paddingBottom: 100 }}>
        <AdminTopBar tab={tab} stats={stats} />

        {tab === 'home' && <DashboardPage data={data} settings={settings} stats={stats} setTab={setTab} openSheet={openSheet} />}
        {tab === 'inventory' && <InventoryPage data={data} settings={settings} stats={stats} openSheet={openSheet} deleteItem={deleteItem} />}
        {tab === 'orders' && <OrdersPage data={data} settings={settings} stats={stats} openSheet={openSheet} deleteItem={deleteItem} onPrintOrder={onPrintOrder} />}
        {tab === 'suppliers' && <SuppliersPage data={data} openSheet={openSheet} deleteItem={deleteItem} />}
        {tab === 'expenses' && <ExpensesPage data={data} settings={settings} openSheet={openSheet} deleteItem={deleteItem} />}
        {tab === 'reports' && <ReportsPage data={data} settings={settings} stats={stats} />}
        {tab === 'integrations' && <IntegrationsPage />}
        {tab === 'api' && <APIManagementPage />}
        {tab === 'monitoring' && <MonitoringPage />}
      </main>

      {/* FAB */}
      <button onClick={fabAction} aria-label="إضافة جديدة" style={{
        position: 'fixed', bottom: 32, left: 32,
        width: 56, height: 56, borderRadius: 999,
        background: T.ink, color: '#fff',
        display: 'grid', placeItems: 'center',
        boxShadow: '0 12px 32px rgba(0,0,0,0.15)',
        zIndex: 40, transition: 'all 200ms ease',
      }}
      onMouseEnter={e => { e.currentTarget.style.background = T.goldUI; e.currentTarget.style.transform = 'scale(1.05)'; }}
      onMouseLeave={e => { e.currentTarget.style.background = T.ink; e.currentTarget.style.transform = 'scale(1)'; }}
      >
        <Plus size={22} />
      </button>
    </div>
  );
}

