// ═══════════════════════════════════════════════════════════════════════
// DASHBOARD PAGE — uses REAL stats
// ═══════════════════════════════════════════════════════════════════════
function DashboardPage({ data, settings, stats, setTab, openSheet }) {
  const insights = useMemo(() => {
    const out = [];
    const bestSellers = Object.values(stats.productStats)
      .filter(ps => ps.soldQty > 0)
      .sort((a, b) => b.soldRevenue - a.soldRevenue);
    const lowStock = Object.values(stats.productStats)
      .filter(ps => ps.remaining > 0 && ps.remaining < settings.lowStockThreshold);
    const outOfStock = Object.values(stats.productStats)
      .filter(ps => ps.remaining <= 0 && ps.product);

    if (bestSellers.length > 0) {
      out.push({
        type: 'success', icon: TrendingUp,
        title: 'الأكثر مبيعاً',
        text: `${bestSellers[0].product.name} يقود مبيعاتك بـ ${bestSellers[0].soldQty} ${bestSellers[0].product.unit === 'gram' ? 'جم' : 'قطعة'}`,
      });
    }
    if (lowStock.length > 0) {
      out.push({
        type: 'warning', icon: AlertCircle,
        title: 'تنبيه مخزون',
        text: `${lowStock.length} منتج بحاجة إعادة طلب: ${lowStock.slice(0, 2).map(ps => ps.product.name).join('، ')}`,
      });
    }
    if (outOfStock.length > 0) {
      out.push({
        type: 'danger', icon: AlertCircle,
        title: 'نفذ المخزون',
        text: `${outOfStock.length} منتج نفذ تماماً`,
      });
    }
    if (stats.margin > 25 && stats.totalSales > 0) {
      out.push({
        type: 'info', icon: Sparkles,
        title: 'هامش ربح ممتاز',
        text: `${stats.margin.toFixed(1)}٪ هامش ربح — أعلى من المتوسط بالقطاع`,
      });
    }
    return out.slice(0, 3);
  }, [stats, settings]);

  const maxWeekly = Math.max(...stats.weekly.map(w => w.total), 1);

  return (
    <div>
      {/* Hero Capital Card */}
      <div style={{
        background: T.bg,
        border: `1px solid ${T.borderLight}`,
        borderTop: `3px solid ${T.goldUI}`,
        padding: '36px 40px', marginBottom: 24,
      }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 40, alignItems: 'center' }}>
          <div>
            <div className="latin-display" style={{
              fontSize: 11, color: T.goldDeep, letterSpacing: 4,
              fontWeight: 500, fontStyle: 'italic', marginBottom: 12,
            }}>Current Capital · رأس المال الحالي</div>
            <div className="mono" style={{
              fontSize: 54, fontWeight: 600, color: T.ink,
              letterSpacing: -1, lineHeight: 1, marginBottom: 14,
            }}>
              {fmt(stats.capital, 0)}
              <span style={{ fontSize: 17, color: T.goldUI, marginRight: 8 }}>د.إ</span>
            </div>
            <div style={{
              display: 'inline-flex', alignItems: 'center', gap: 6,
              fontSize: 12, fontWeight: 700,
              color: stats.netProfit >= 0 ? T.green : T.red,
              padding: '5px 12px',
              background: stats.netProfit >= 0 ? T.greenSoft : T.redSoft,
            }}>
              {stats.netProfit >= 0 ? <TrendingUp size={13} /> : <TrendingDown size={13} />}
              {stats.netProfit >= 0 ? '+' : ''}{fmt(stats.netProfit, 0)} د.إ صافي ربح
            </div>
            <div style={{
              display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)',
              gap: 24, marginTop: 28, paddingTop: 20,
              borderTop: `1px solid ${T.borderLight}`,
            }}>
              {[
                { label: 'Total Sales', value: fmt(stats.totalSales, 0), color: T.ink },
                { label: 'Orders', value: stats.ordersCount, color: T.ink },
                { label: 'Margin', value: `${stats.margin.toFixed(1)}%`, color: stats.margin >= 0 ? T.green : T.red },
              ].map((s, i) => (
                <div key={i}>
                  <div className="latin-display" style={{
                    fontSize: 10, color: T.faint, letterSpacing: 2,
                    marginBottom: 4, fontStyle: 'italic',
                  }}>{s.label}</div>
                  <div className="mono" style={{ fontSize: 20, fontWeight: 600, color: s.color }}>
                    {s.value}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Live chart */}
          <div>
            <div style={{ fontSize: 11, color: T.muted, marginBottom: 8 }}>المبيعات (آخر 14 يوم)</div>
            <div style={{ height: 140, display: 'flex', alignItems: 'flex-end', gap: 4 }}>
              {stats.weekly.map((w, i) => (
                <div key={i} title={`${w.date}: ${fmt(w.total, 0)} د.إ`} style={{
                  flex: 1,
                  height: `${(w.total / maxWeekly) * 100}%`,
                  background: i === stats.weekly.length - 1 ? T.goldUI : T.goldDecor,
                  opacity: w.total > 0 ? (i === stats.weekly.length - 1 ? 1 : 0.4) : 0.1,
                  minHeight: 2, transition: 'all 300ms ease',
                }} />
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* KPI Row */}
      <div style={{
        display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
        gap: 16, marginBottom: 28,
      }}>
        <KPI icon={Wallet} label="إجمالي المبيعات" value={fmt(stats.totalSales, 0)} unit="د.إ" />
        <KPI icon={Boxes} label="قيمة المخزون" value={fmt(stats.stockValue, 0)} unit="د.إ" />
        <KPI icon={Receipt} label="إجمالي المصاريف" value={fmt(stats.totalExpenses, 0)} unit="د.إ" />
        <KPI icon={Package} label="عدد المنتجات" value={data.products.length} />
      </div>

      {/* Smart Insights */}
      {insights.length > 0 && (
        <div style={{ marginBottom: 28 }}>
          <h2 className="arabic-display" style={{
            fontSize: 22, fontWeight: 500, color: T.ink, marginBottom: 16,
            display: 'flex', alignItems: 'center', gap: 10,
          }}>
            <Sparkles size={18} style={{ color: T.goldUI }} strokeWidth={1.5} />
            تنبيهات ذكية
          </h2>
          <div style={{
            display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: 16,
          }}>
            {insights.map((ins, i) => (
              <Insight key={i} type={ins.type} icon={ins.icon} title={ins.title} text={ins.text} />
            ))}
          </div>
        </div>
      )}

      {/* Recent Orders + Quick Actions */}
      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: 20 }}>
        <Card title="آخر الطلبات" kicker="Recent Orders" action="عرض الكل" onAction={() => setTab('orders')}>
          {data.orders.slice(0, 5).map((o, i, arr) => {
            const baseTotal = toBase(o.total || 0, o.currency || 'AED', settings.fxRates);
            return (
              <div key={o.id} style={{
                display: 'grid', gridTemplateColumns: '1fr auto auto', gap: 16,
                alignItems: 'center', padding: '14px 0',
                borderBottom: i < arr.length - 1 ? `1px solid ${T.borderLight}` : 'none',
              }}>
                <div>
                  <div style={{ fontSize: 14, fontWeight: 600, color: T.ink, marginBottom: 3 }}>
                    {o.customerName}
                  </div>
                  <div className="mono" style={{ fontSize: 11, color: T.muted }}>
                    {o.city} · {fmtDate(o.date)}
                  </div>
                </div>
                <span style={{
                  fontSize: 10, fontWeight: 700, padding: '4px 10px',
                  background: o.paymentStatus === 'paid' ? T.greenSoft : T.amberSoft,
                  color: o.paymentStatus === 'paid' ? T.green : T.amber,
                  letterSpacing: 0.5,
                }}>
                  {o.paymentStatus === 'paid' ? 'مدفوع' : o.paymentStatus === 'partial' ? 'جزئي' : 'آجل'}
                </span>
                <div className="mono" style={{
                  fontSize: 15, fontWeight: 600, color: T.ink,
                  minWidth: 100, textAlign: 'left',
                }}>
                  {fmt(baseTotal, 0)} <span style={{ fontSize: 10, color: T.muted }}>د.إ</span>
                </div>
              </div>
            );
          })}
        </Card>

        <Card title="إجراءات سريعة" kicker="Quick Actions">
          {[
            { icon: Plus, label: 'طلب جديد', action: () => openSheet({ type: 'order' }) },
            { icon: Package, label: 'منتج جديد', action: () => openSheet({ type: 'product' }) },
            { icon: Truck, label: 'تسجيل شراء', action: () => openSheet({ type: 'purchase' }) },
            { icon: Receipt, label: 'تسجيل مصروف', action: () => openSheet({ type: 'expense' }) },
          ].map((a, i) => (
            <button key={i} onClick={a.action} style={{
              display: 'flex', alignItems: 'center', gap: 12,
              padding: '12px 14px', fontSize: 13, fontWeight: 500,
              color: T.ink, background: T.bg,
              border: `1px solid ${T.borderLight}`,
              textAlign: 'right', width: '100%',
              minHeight: 44, marginBottom: 8,
              transition: 'all 180ms ease',
            }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = T.goldUI; e.currentTarget.style.background = T.goldFaint; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = T.borderLight; e.currentTarget.style.background = T.bg; }}
            >
              <a.icon size={16} style={{ color: T.goldUI }} strokeWidth={1.5} />
              {a.label}
            </button>
          ))}
        </Card>
      </div>
    </div>
  );
}

function KPI({ icon: Icon, label, value, unit }) {
  return (
    <div style={{ background: T.bg, border: `1px solid ${T.borderLight}`, padding: 20 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
        <Icon size={18} style={{ color: T.goldUI }} strokeWidth={1.5} />
      </div>
      <div style={{ fontSize: 11, color: T.muted, marginBottom: 4 }}>{label}</div>
      <div className="mono" style={{ fontSize: 26, fontWeight: 600, color: T.ink }}>
        {value}
        {unit && <span style={{ fontSize: 12, color: T.goldUI, marginRight: 4 }}>{unit}</span>}
      </div>
    </div>
  );
}

function Insight({ type, icon: Icon, title, text }) {
  const colors = {
    success: T.green, warning: T.amber, info: T.goldUI, danger: T.red,
  };
  const accent = colors[type] || T.goldUI;
  return (
    <div style={{
      padding: 18, background: T.bg,
      border: `1px solid ${T.borderLight}`,
      borderRight: `3px solid ${accent}`,
    }}>
      <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12 }}>
        <Icon size={18} style={{ color: accent, marginTop: 2 }} strokeWidth={1.5} />
        <div>
          <div style={{ fontSize: 13, fontWeight: 700, color: T.ink, marginBottom: 4 }}>{title}</div>
          <div style={{ fontSize: 12, color: T.muted, lineHeight: 1.6 }}>{text}</div>
        </div>
      </div>
    </div>
  );
}

function Card({ title, kicker, action, onAction, children }) {
  return (
    <div style={{ background: T.bg, border: `1px solid ${T.borderLight}`, padding: 24 }}>
      <div style={{
        display: 'flex', justifyContent: 'space-between',
        alignItems: 'flex-start', marginBottom: 16,
      }}>
        <div>
          {kicker && (
            <div className="latin-display" style={{
              fontSize: 10, color: T.goldDeep, letterSpacing: 3,
              fontWeight: 500, fontStyle: 'italic', marginBottom: 4,
            }}>{kicker}</div>
          )}
          <h3 className="arabic-display" style={{ fontSize: 18, fontWeight: 500, color: T.ink }}>{title}</h3>
        </div>
        {action && (
          <button onClick={onAction} style={{ fontSize: 11, color: T.goldDeep, fontWeight: 600, letterSpacing: 0.5 }}>
            {action} ←
          </button>
        )}
      </div>
      <div>{children}</div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════
// INVENTORY PAGE — Real stock tracking
// ═══════════════════════════════════════════════════════════════════════
function InventoryPage({ data, settings, stats, openSheet, deleteItem }) {
  const [search, setSearch] = useState('');
  const filtered = data.products.filter(p => !search || p.name.toLowerCase().includes(search.toLowerCase()) || p.origin.toLowerCase().includes(search.toLowerCase()));

  return (
    <div>
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        marginBottom: 20, gap: 12,
      }}>
        <div style={{ position: 'relative', flex: 1, maxWidth: 320 }}>
          <Search size={14} style={{ position: 'absolute', right: 12, top: '50%', transform: 'translateY(-50%)', color: T.muted }} strokeWidth={1.5} />
          <input
            value={search} onChange={e => setSearch(e.target.value)}
            placeholder="بحث في المنتجات..."
            style={{
              width: '100%', padding: '10px 36px 10px 12px',
              background: T.bg, border: `1px solid ${T.borderLight}`,
              outline: 'none', fontSize: 13,
            }}
          />
        </div>
        <button onClick={() => openSheet({ type: 'purchase' })} style={{
          padding: '10px 16px', background: T.bg,
          border: `1px solid ${T.goldUI}`, color: T.goldUI,
          fontSize: 12, fontWeight: 700, letterSpacing: 1,
          display: 'flex', alignItems: 'center', gap: 6,
          minHeight: 40,
        }}>
          <Plus size={14} />
          تسجيل شراء
        </button>
      </div>

      <div style={{
        display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 16,
      }}>
        {filtered.map(p => {
          const ps = stats.productStats[p.id] || { remaining: 0, avgCost: 0, stockValue: 0, soldQty: 0 };
          const low = ps.remaining > 0 && ps.remaining < settings.lowStockThreshold;
          const out = ps.remaining <= 0;
          return (
            <div key={p.id} style={{
              background: T.bg, border: `1px solid ${T.borderLight}`, padding: 18,
            }}>
              <div style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start',
                marginBottom: 12,
              }}>
                <div style={{ flex: 1 }}>
                  <div className="arabic-display" style={{ fontSize: 16, fontWeight: 600, color: T.ink, marginBottom: 4 }}>
                    {p.name}
                  </div>
                  <div style={{ fontSize: 11, color: T.muted }}>{p.origin} · {p.type}</div>
                </div>
                <span style={{
                  fontSize: 10, fontWeight: 700, padding: '3px 8px',
                  background: out ? T.redSoft : low ? T.amberSoft : T.greenSoft,
                  color: out ? T.red : low ? T.amber : T.green,
                }}>
                  {out ? 'نفذ' : low ? 'منخفض' : 'متوفر'}
                </span>
              </div>

              <div style={{ display: 'flex', gap: 6, marginBottom: 14, flexWrap: 'wrap' }}>
                <span className="mono" style={{
                  padding: '3px 8px', background: T.goldFaint,
                  color: T.goldDeep, fontSize: 10, fontWeight: 700,
                  border: `1px solid ${T.goldDecor}40`,
                }}>{p.grade}</span>
                <span style={{
                  padding: '3px 8px', background: T.paper,
                  color: T.muted, fontSize: 10, fontWeight: 600,
                }}>{p.origin}</span>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 14, fontSize: 12 }}>
                <div>
                  <div style={{ color: T.muted, marginBottom: 2 }}>المتبقي</div>
                  <div className="mono" style={{ fontWeight: 600, color: T.ink }}>
                    {p.unit === 'gram' ? fmtWeight(Math.max(0, ps.remaining)) : `${Math.max(0, ps.remaining)} قطعة`}
                  </div>
                </div>
                <div>
                  <div style={{ color: T.muted, marginBottom: 2 }}>سعر البيع</div>
                  <div className="mono" style={{ fontWeight: 600, color: T.ink }}>
                    {fmt(p.salePrice, 0)} د.إ
                  </div>
                </div>
                <div>
                  <div style={{ color: T.muted, marginBottom: 2 }}>متوسط التكلفة</div>
                  <div className="mono" style={{ fontWeight: 600, color: T.muted }}>
                    {fmt(ps.avgCost, 2)} د.إ
                  </div>
                </div>
                <div>
                  <div style={{ color: T.muted, marginBottom: 2 }}>قيمة المخزون</div>
                  <div className="mono" style={{ fontWeight: 600, color: T.goldDeep }}>
                    {fmt(ps.stockValue, 0)} د.إ
                  </div>
                </div>
              </div>

              <div style={{
                display: 'flex', gap: 6, paddingTop: 12,
                borderTop: `1px solid ${T.borderLight}`,
              }}>
                <button onClick={() => openSheet({ type: 'product', id: p.id })} style={{
                  flex: 1, padding: '8px', fontSize: 11, color: T.ink,
                  border: `1px solid ${T.borderLight}`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4,
                  minHeight: 36,
                }}>
                  <Edit3 size={12} />
                  تعديل
                </button>
                <button onClick={() => deleteItem('product', p.id, p.name)} style={{
                  width: 36, height: 36,
                  border: `1px solid ${T.borderLight}`,
                  color: T.red,
                  display: 'grid', placeItems: 'center',
                }}>
                  <Trash2 size={13} />
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════
// ORDERS PAGE
// ═══════════════════════════════════════════════════════════════════════
function OrdersPage({ data, settings, stats, openSheet, deleteItem, onPrintOrder }) {
  const sorted = [...data.orders].sort((a, b) => new Date(b.date) - new Date(a.date));

  return (
    <div style={{ background: T.bg, border: `1px solid ${T.borderLight}`, padding: 24 }}>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr>
            {['الطلب', 'العميل', 'المدينة', 'العملة', 'الإجمالي', 'الحالة', 'التاريخ', ''].map(h => (
              <th key={h} style={{
                textAlign: 'right', padding: '12px 12px',
                fontSize: 10, color: T.muted, fontWeight: 700, letterSpacing: 1,
                borderBottom: `2px solid ${T.borderLight}`,
              }}>{h}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sorted.map((o, i, arr) => {
            const baseTotal = toBase(o.total || 0, o.currency || 'AED', settings.fxRates);
            return (
              <tr key={o.id} style={{ borderBottom: i < arr.length - 1 ? `1px solid ${T.borderLight}` : 'none' }}>
                <td className="mono" style={{ padding: '12px', fontSize: 11, color: T.muted }}>
                  #{o.id.slice(-6).toUpperCase()}
                </td>
                <td style={{ padding: '12px', fontSize: 14, color: T.ink, fontWeight: 600 }}>{o.customerName}</td>
                <td style={{ padding: '12px', fontSize: 13, color: T.muted }}>{o.city}</td>
                <td className="mono" style={{ padding: '12px', fontSize: 11, color: T.muted }}>{o.currency}</td>
                <td className="mono" style={{ padding: '12px', fontSize: 14, fontWeight: 600, color: T.ink }}>
                  {fmt(o.total, 0)}
                  {o.currency !== 'AED' && <span style={{ fontSize: 10, color: T.muted, marginRight: 6 }}>≈ {fmt(baseTotal, 0)} د.إ</span>}
                </td>
                <td style={{ padding: '12px' }}>
                  <span style={{
                    fontSize: 10, fontWeight: 700, padding: '4px 10px',
                    background: o.paymentStatus === 'paid' ? T.greenSoft : T.amberSoft,
                    color: o.paymentStatus === 'paid' ? T.green : T.amber,
                  }}>
                    {o.paymentStatus === 'paid' ? 'مدفوع' : o.paymentStatus === 'partial' ? 'جزئي' : 'آجل'}
                  </span>
                </td>
                <td style={{ padding: '12px', fontSize: 12, color: T.muted }}>{fmtDate(o.date)}</td>
                <td style={{ padding: '12px', textAlign: 'left' }}>
                  <div style={{ display: 'flex', gap: 4, justifyContent: 'flex-start' }}>
                    <button onClick={() => onPrintOrder(o)} style={{
                      width: 30, height: 30, color: T.muted,
                      border: `1px solid ${T.borderLight}`,
                      display: 'grid', placeItems: 'center',
                    }} aria-label="طباعة">
                      <Printer size={12} />
                    </button>
                    <button onClick={() => openSheet({ type: 'order', id: o.id })} style={{
                      width: 30, height: 30, color: T.muted,
                      border: `1px solid ${T.borderLight}`,
                      display: 'grid', placeItems: 'center',
                    }} aria-label="تعديل">
                      <Edit3 size={12} />
                    </button>
                    <button onClick={() => deleteItem('order', o.id, o.customerName)} style={{
                      width: 30, height: 30, color: T.red,
                      border: `1px solid ${T.borderLight}`,
                      display: 'grid', placeItems: 'center',
                    }} aria-label="حذف">
                      <Trash2 size={12} />
                    </button>
                  </div>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

