// SUPPLIERS PAGE — with WhatsApp + Stars
// ═══════════════════════════════════════════════════════════════════════
function SuppliersPage({ data, openSheet, deleteItem }) {
  return (
    <div style={{
      display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: 16,
    }}>
      {data.suppliers.map(s => {
        const supplierPurchases = data.purchases.filter(p => p.supplierId === s.id);
        return (
          <div key={s.id} style={{
            background: T.bg, border: `1px solid ${T.borderLight}`, padding: 20,
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
              <div>
                <div className="arabic-display" style={{ fontSize: 17, fontWeight: 600, color: T.ink, marginBottom: 4 }}>
                  {s.name}
                </div>
                <div style={{ fontSize: 12, color: T.muted }}>{s.country}</div>
              </div>
              <div style={{ display: 'flex', gap: 2 }}>
                {[1,2,3,4,5].map(i => (
                  <Star key={i} size={12} fill={i <= s.rating ? T.goldUI : 'none'} stroke={i <= s.rating ? T.goldUI : T.faint} strokeWidth={1.5} />
                ))}
              </div>
            </div>

            <div style={{ display: 'flex', gap: 6, marginBottom: 14 }}>
              {s.phone && (
                <a href={`tel:${s.phone}`} style={{
                  flex: 1, padding: '8px',
                  background: T.paper, border: `1px solid ${T.borderLight}`,
                  fontSize: 11, color: T.ink, fontWeight: 600,
                  display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
                  minHeight: 36,
                }}>
                  <Phone size={12} />
                  اتصال
                </a>
              )}
              {s.whatsapp && (
                <a href={`https://wa.me/${s.whatsapp.replace(/[^0-9]/g, '')}`} target="_blank" rel="noopener noreferrer" style={{
                  flex: 1, padding: '8px',
                  background: T.greenSoft, border: `1px solid ${T.green}40`,
                  fontSize: 11, color: T.green, fontWeight: 600,
                  display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
                  minHeight: 36,
                }}>
                  <MessageCircle size={12} />
                  واتساب
                </a>
              )}
            </div>

            {s.notes && (
              <div style={{
                fontSize: 12, color: T.muted, lineHeight: 1.6,
                padding: '8px 10px', background: T.paper,
                marginBottom: 14,
              }}>{s.notes}</div>
            )}

            <div style={{
              display: 'flex', justifyContent: 'space-between',
              fontSize: 11, color: T.muted,
              paddingTop: 12, borderTop: `1px solid ${T.borderLight}`,
              marginBottom: 12,
            }}>
              <span>عدد المشتريات: <strong style={{ color: T.ink }}>{supplierPurchases.length}</strong></span>
            </div>

            <div style={{ display: 'flex', gap: 6 }}>
              <button onClick={() => openSheet({ type: 'supplier', id: s.id })} style={{
                flex: 1, padding: '8px', fontSize: 11, color: T.ink,
                border: `1px solid ${T.borderLight}`,
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4,
                minHeight: 36,
              }}>
                <Edit3 size={12} />
                تعديل
              </button>
              <button onClick={() => deleteItem('supplier', s.id, s.name)} style={{
                width: 36, height: 36, color: T.red,
                border: `1px solid ${T.borderLight}`,
                display: 'grid', placeItems: 'center',
              }}>
                <Trash2 size={13} />
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
}

