                  <button onClick={() => openSheet({ type: 'expense', id: e.id })} style={{
                    width: 30, height: 30, color: T.muted,
                    border: `1px solid ${T.borderLight}`,
                    display: 'grid', placeItems: 'center',
                  }}><Edit3 size={12} /></button>
