function PurchaseForm({ sheet, data, settings, onSave, onClose }) {
  const [f, setF] = useState({
    productId: '', supplierId: '', quantity: 0,
    unitCost: 0, totalCost: 0,
    currency: 'AED', date: todayISO(),
  });
  const u = (k, v) => setF(p => ({ ...p, [k]: v }));

  useEffect(() => {
    if (f.quantity && f.unitCost) {
      u('totalCost', Number(f.quantity) * Number(f.unitCost));
    }
  }, [f.quantity, f.unitCost]);

  return (
    <Sheet title="تسجيل عملية شراء" onClose={onClose}>
      <Field label="المنتج">
        <select value={f.productId} onChange={e => u('productId', e.target.value)} style={inputStyle}>
          <option value="">اختر منتج...</option>
          {data.products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
      </Field>
      <Field label="المورد">
        <select value={f.supplierId} onChange={e => u('supplierId', e.target.value)} style={inputStyle}>
          <option value="">اختر مورد...</option>
          {data.suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
        </select>
      </Field>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
        <Field label="الكمية">
          <input type="number" value={f.quantity} onChange={e => u('quantity', Number(e.target.value))} style={inputStyle} />
        </Field>
        <Field label="سعر الوحدة">
          <input type="number" value={f.unitCost} onChange={e => u('unitCost', Number(e.target.value))} style={inputStyle} step="0.01" />
        </Field>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
        <Field label="الإجمالي">
          <input type="number" value={f.totalCost} onChange={e => u('totalCost', Number(e.target.value))} style={inputStyle} />
        </Field>
        <Field label="العملة">
          <select value={f.currency} onChange={e => u('currency', e.target.value)} style={inputStyle}>
            {CURRENCIES.map(c => <option key={c}>{c}</option>)}
          </select>
        </Field>
      </div>
      <Field label="التاريخ">
        <input type="date" value={f.date} onChange={e => u('date', e.target.value)} style={inputStyle} />
      </Field>

      {f.totalCost > 0 && f.currency !== 'AED' && (
        <div style={{
          padding: 12, background: T.goldFaint,
          border: `1px solid ${T.goldDecor}40`,
          fontSize: 12, color: T.goldDeep, marginBottom: 16,
        }}>
          ≈ {fmt(toBase(f.totalCost, f.currency, settings.fxRates), 2)} د.إ
        </div>
      )}

      <div style={{ display: 'flex', gap: 8, marginTop: 8, paddingTop: 16, borderTop: `1px solid ${T.borderLight}` }}>
        <button onClick={onClose} style={{
          flex: 1, padding: '12px',
          border: `1px solid ${T.borderLight}`, color: T.ink,
          fontSize: 13, fontWeight: 600, minHeight: 44,
        }}>إلغاء</button>
        <button onClick={() => onSave(f)} disabled={!f.productId || !f.quantity} style={{
          flex: 2, padding: '12px',
          background: (!f.productId || !f.quantity) ? T.faint : T.ink, color: '#fff',
          fontSize: 13, fontWeight: 700, letterSpacing: 1, minHeight: 44,
        }}>تسجيل الشراء</button>
      </div>
    </Sheet>
  );
}

function OrderForm({ sheet, data, settings, onSave, onClose }) {
  const existing = sheet.id ? data.orders.find(o => o.id === sheet.id) : null;
  const [f, setF] = useState(existing || {
    customerName: '', city: '', date: todayISO(),
    currency: 'AED', paymentStatus: 'paid',
    items: [],
  });
  const u = (k, v) => setF(p => ({ ...p, [k]: v }));

  const total = useMemo(() => f.items.reduce((s, i) => s + (Number(i.quantity || 0) * Number(i.unitPrice || 0)), 0), [f.items]);

  const addItem = () => {
    u('items', [...f.items, { productId: '', quantity: 1, unitPrice: 0, unitCost: 0 }]);
  };
  const updateItem = (idx, key, val) => {
    const newItems = [...f.items];
    newItems[idx] = { ...newItems[idx], [key]: val };
    if (key === 'productId') {
      const p = data.products.find(pp => pp.id === val);
      if (p) newItems[idx].unitPrice = p.salePrice;
    }
    u('items', newItems);
  };
  const removeItem = (idx) => u('items', f.items.filter((_, i) => i !== idx));

  return (
    <Sheet title={existing ? 'تعديل طلب' : 'طلب جديد'} onClose={onClose}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
        <Field label="اسم العميل">
          <input value={f.customerName} onChange={e => u('customerName', e.target.value)} style={inputStyle} />
        </Field>
        <Field label="المدينة">
          <input value={f.city} onChange={e => u('city', e.target.value)} style={inputStyle} />
        </Field>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 12 }}>
        <Field label="التاريخ">
          <input type="date" value={f.date} onChange={e => u('date', e.target.value)} style={inputStyle} />
        </Field>
        <Field label="العملة">
          <select value={f.currency} onChange={e => u('currency', e.target.value)} style={inputStyle}>
            {CURRENCIES.map(c => <option key={c}>{c}</option>)}
          </select>
        </Field>
        <Field label="الحالة">
          <select value={f.paymentStatus} onChange={e => u('paymentStatus', e.target.value)} style={inputStyle}>
            <option value="paid">مدفوع</option>
            <option value="partial">جزئي</option>
            <option value="pending">آجل</option>
          </select>
        </Field>
      </div>

      <div style={{ marginTop: 8, marginBottom: 16 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
          <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, letterSpacing: 1 }}>المنتجات</label>
          <button onClick={addItem} style={{
            fontSize: 12, fontWeight: 600, color: T.goldUI,
            display: 'flex', alignItems: 'center', gap: 4,
          }}>
            <Plus size={14} />
            إضافة منتج
          </button>
        </div>
        {f.items.length === 0 && (
          <div style={{
            padding: 20, background: T.paper, textAlign: 'center',
            fontSize: 13, color: T.muted,
            border: `1px dashed ${T.borderLight}`,
          }}>
            اضغط "إضافة منتج" لبدء الطلب
          </div>
        )}
        {f.items.map((item, idx) => (
          <div key={idx} style={{
            display: 'grid', gridTemplateColumns: '2fr 80px 100px auto',
            gap: 8, marginBottom: 8, alignItems: 'center',
          }}>
            <select value={item.productId} onChange={e => updateItem(idx, 'productId', e.target.value)} style={{ ...inputStyle, minHeight: 40 }}>
              <option value="">اختر منتج...</option>
              {data.products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
            <input type="number" value={item.quantity} onChange={e => updateItem(idx, 'quantity', Number(e.target.value))} placeholder="الكمية" style={{ ...inputStyle, minHeight: 40 }} />
            <input type="number" value={item.unitPrice} onChange={e => updateItem(idx, 'unitPrice', Number(e.target.value))} placeholder="السعر" style={{ ...inputStyle, minHeight: 40 }} />
            <button onClick={() => removeItem(idx)} style={{
              width: 36, height: 40, color: T.red,
              border: `1px solid ${T.borderLight}`,
              display: 'grid', placeItems: 'center',
            }}>
              <X size={14} />
            </button>
          </div>
        ))}
      </div>

      {total > 0 && (
        <div style={{
          padding: 14, background: T.goldFaint,
          border: `1px solid ${T.goldDecor}40`,
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          marginBottom: 16,
        }}>
          <span style={{ fontSize: 13, color: T.goldDeep, fontWeight: 700 }}>الإجمالي</span>
          <span className="mono" style={{ fontSize: 18, fontWeight: 700, color: T.goldUI }}>
            {fmt(total, 0)} <span style={{ fontSize: 12 }}>{f.currency}</span>
          </span>
        </div>
      )}

      <div style={{ display: 'flex', gap: 8, paddingTop: 16, borderTop: `1px solid ${T.borderLight}` }}>
        <button onClick={onClose} style={{
          flex: 1, padding: '12px',
          border: `1px solid ${T.borderLight}`, color: T.ink,
          fontSize: 13, fontWeight: 600, minHeight: 44,
        }}>إلغاء</button>
        <button onClick={() => onSave({ ...f, id: existing?.id, total })} disabled={!f.customerName || f.items.length === 0} style={{
          flex: 2, padding: '12px',
          background: (!f.customerName || f.items.length === 0) ? T.faint : T.ink, color: '#fff',
          fontSize: 13, fontWeight: 700, letterSpacing: 1, minHeight: 44,
        }}>{existing ? 'تحديث' : 'حفظ الطلب'}</button>
      </div>
    </Sheet>
  );
}

