// ═══════════════════════════════════════════════════════════════════════
// SETTINGS / LOGS / BACKUP / INVOICE / CONFIRM / TOAST
// ═══════════════════════════════════════════════════════════════════════
function SettingsSheet({ settings, setSettings, onClose, onChange }) {
  const [s, setS] = useState(settings);

  const save = () => {
    setSettings(s);
    onChange && onChange();
    onClose();
  };

  return (
    <Sheet title="الإعدادات" onClose={onClose}>
      <Field label="رأس المال الابتدائي">
        <input type="number" value={s.capital} onChange={e => setS({ ...s, capital: Number(e.target.value) })} style={inputStyle} />
      </Field>
      <Field label="حد المخزون المنخفض">
        <input type="number" value={s.lowStockThreshold} onChange={e => setS({ ...s, lowStockThreshold: Number(e.target.value) })} style={inputStyle} />
      </Field>
      <div style={{ marginTop: 8 }}>
        <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, letterSpacing: 1, marginBottom: 10, display: 'block' }}>
          أسعار الصرف (مقابل د.إ)
        </label>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
          {Object.keys(s.fxRates).filter(c => c !== 'AED').map(c => (
            <Field key={c} label={`1 ${c} = ؟ د.إ`}>
              <input type="number" value={s.fxRates[c]} onChange={e => setS({ ...s, fxRates: { ...s.fxRates, [c]: Number(e.target.value) } })} step="0.001" style={inputStyle} />
            </Field>
          ))}
        </div>
      </div>

      <div style={{ display: 'flex', gap: 8, marginTop: 24, paddingTop: 16, borderTop: `1px solid ${T.borderLight}` }}>
        <button onClick={onClose} style={{
          flex: 1, padding: '12px',
          border: `1px solid ${T.borderLight}`, color: T.ink,
          fontSize: 13, fontWeight: 600, minHeight: 44,
        }}>إلغاء</button>
        <button onClick={save} style={{
          flex: 2, padding: '12px',
          background: T.ink, color: '#fff',
          fontSize: 13, fontWeight: 700, letterSpacing: 1, minHeight: 44,
        }}>حفظ</button>
      </div>
    </Sheet>
  );
}

function LogsSheet({ logs, onClose }) {
  const [filter, setFilter] = useState('all');
  const filtered = filter === 'all' ? logs : logs.filter(l => l.type === filter);

  const typeColor = (t) => {
    if (t === 'error') return T.red;
    if (t === 'warning') return T.amber;
    if (t === 'transaction') return T.green;
    return T.muted;
  };

  return (
    <Sheet title={`سجل العمليات (${logs.length})`} onClose={onClose}>
      <div style={{ display: 'flex', gap: 6, marginBottom: 16, overflowX: 'auto', paddingBottom: 4 }}>
        {[
          { id: 'all', label: 'الكل' },
          { id: 'transaction', label: 'العمليات' },
          { id: 'info', label: 'معلومات' },
          { id: 'warning', label: 'تحذيرات' },
          { id: 'error', label: 'أخطاء' },
        ].map(f => (
          <button key={f.id} onClick={() => setFilter(f.id)} style={{
            padding: '6px 14px', fontSize: 11, fontWeight: 600,
            background: filter === f.id ? T.ink : T.bg,
            color: filter === f.id ? '#fff' : T.ink,
            border: `1px solid ${filter === f.id ? T.ink : T.borderLight}`,
            whiteSpace: 'nowrap',
          }}>{f.label}</button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 40, color: T.muted, fontSize: 13 }}>لا توجد سجلات</div>
      ) : (
        filtered.map(log => (
          <div key={log.id} style={{
            padding: '12px 0',
            borderBottom: `1px solid ${T.borderLight}`,
            display: 'flex', gap: 12,
          }}>
            <div style={{
              width: 8, height: 8, borderRadius: 999,
              background: typeColor(log.type),
              marginTop: 7, flexShrink: 0,
            }} />
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13, color: T.ink, marginBottom: 4 }}>{log.message}</div>
              <div className="mono" style={{ fontSize: 10, color: T.faint }}>
                {new Date(log.date).toLocaleString('ar-AE')}
              </div>
            </div>
          </div>
        ))
      )}
    </Sheet>
  );
}

