function IntegrationsPage() {
  const [section, setSection] = useState('overview');
  const [env, setEnv] = useState('production');
  const [selected, setSelected] = useState(null);
  const [showSetup, setShowSetup] = useState(false);

  const sections = [
    { id: 'overview', label: 'نظرة عامة', icon: Layers },
    { id: 'payments', label: 'بوابات الدفع', icon: Wallet, count: 8 },
    { id: 'whatsapp', label: 'WhatsApp', icon: MessageCircle, count: 2 },
    { id: 'shipping', label: 'شركات الشحن', icon: Truck, count: 6 },
    { id: 'email', label: 'البريد الإلكتروني', icon: Mail, count: 4 },
    { id: 'sms', label: 'الرسائل القصيرة', icon: Smartphone, count: 2 },
  ];

  // Stats for overview
  const stats = useMemo(() => {
    let connected = 0, failed = 0, total = 0;
    Object.values(INTEGRATIONS_DATA).forEach(arr => {
      arr.forEach(item => {
        total++;
        if (item.status === 'connected') connected++;
        else if (item.status === 'failed' || item.status === 'expired') failed++;
      });
    });
    return { connected, failed, total, disconnected: total - connected - failed };
  }, []);

  return (
    <div>
      {/* Top: Environment + Description */}
      <div style={{
        background: T.bg, border: `1px solid ${T.borderLight}`,
        padding: '20px 24px', marginBottom: 20,
        display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 16,
      }}>
        <div>
          <div className="latin-display" style={{
            fontSize: 11, color: T.goldDeep, letterSpacing: 4,
            fontStyle: 'italic', fontWeight: 500, marginBottom: 4,
          }}>System Integrations</div>
          <div style={{ fontSize: 13, color: T.muted }}>
            إدارة جميع الخدمات الخارجية والـ APIs المربوطة بالنظام
          </div>
        </div>
        <EnvSwitcher env={env} setEnv={setEnv} />
      </div>

      {/* Section tabs */}
      <div style={{
        display: 'flex', gap: 4, marginBottom: 24, overflowX: 'auto',
        padding: '0 0 4px',
      }}>
        {sections.map(s => (
          <button key={s.id} onClick={() => setSection(s.id)} style={{
            padding: '10px 18px',
            background: section === s.id ? T.ink : T.bg,
            color: section === s.id ? '#fff' : T.ink,
            border: `1px solid ${section === s.id ? T.ink : T.borderLight}`,
            fontSize: 12, fontWeight: 700, letterSpacing: 0.5,
            display: 'flex', alignItems: 'center', gap: 8,
            whiteSpace: 'nowrap', minHeight: 40,
            transition: 'all 180ms ease',
          }}>
            <s.icon size={14} strokeWidth={1.5} />
            {s.label}
            {s.count && (
              <span style={{
                padding: '1px 6px',
                background: section === s.id ? 'rgba(255,255,255,0.2)' : T.goldFaint,
                color: section === s.id ? '#fff' : T.goldDeep,
                fontSize: 10, fontWeight: 700,
              }}>{s.count}</span>
            )}
          </button>
        ))}
      </div>

      {section === 'overview' && <IntegrationsOverview stats={stats} />}
      {section === 'payments' && <IntegrationsList items={INTEGRATIONS_DATA.payments} category="payments" onSelect={(item) => { setSelected(item); setShowSetup(true); }} />}
      {section === 'whatsapp' && <IntegrationsList items={INTEGRATIONS_DATA.whatsapp} category="whatsapp" onSelect={(item) => { setSelected(item); setShowSetup(true); }} />}
      {section === 'shipping' && <IntegrationsList items={INTEGRATIONS_DATA.shipping} category="shipping" onSelect={(item) => { setSelected(item); setShowSetup(true); }} />}
      {section === 'email' && <IntegrationsList items={INTEGRATIONS_DATA.email} category="email" onSelect={(item) => { setSelected(item); setShowSetup(true); }} />}
      {section === 'sms' && <IntegrationsList items={INTEGRATIONS_DATA.sms} category="sms" onSelect={(item) => { setSelected(item); setShowSetup(true); }} />}

      {showSetup && selected && (
        <IntegrationSetupSheet
          integration={selected}
          onClose={() => { setShowSetup(false); setSelected(null); }}
        />
      )}
    </div>
  );
}

