function IntegrationSetupSheet({ integration, onClose }) {
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState(null);
  const [fields, setFields] = useState({});
  const [mode, setMode] = useState(integration.mode || 'sandbox');

  const fieldLabels = {
    apiKey: 'API Key',
    secretKey: 'Secret Key',
    webhookSecret: 'Webhook Secret',
    merchantId: 'Merchant ID',
    publicKey: 'Public Key',
    apiToken: 'API Token',
    notificationToken: 'Notification Token',
    profileId: 'Profile ID',
    serverKey: 'Server Key',
    baseUrl: 'Base URL',
    clientId: 'Client ID',
    clientSecret: 'Client Secret',
    accessToken: 'Access Token',
    phoneNumberId: 'Phone Number ID',
    businessAccountId: 'Business Account ID',
    verifyToken: 'Verify Token',
    accountSid: 'Account SID',
    authToken: 'Auth Token',
    whatsappNumber: 'WhatsApp Number',
    username: 'Username',
    password: 'Password',
    accountNumber: 'Account Number',
    pin: 'PIN',
    passKey: 'Pass Key',
    customerId: 'Customer ID',
    secret: 'Secret',
    apiSecret: 'API Secret',
    domain: 'Domain',
    region: 'Region',
    fromEmail: 'From Email',
    fromName: 'From Name',
    host: 'SMTP Host',
    port: 'Port',
    appSid: 'App SID',
    senderId: 'Sender ID',
    fromNumber: 'From Number',
  };

  const handleTest = () => {
    setTesting(true);
    setTestResult(null);
    setTimeout(() => {
      setTesting(false);
      setTestResult(Math.random() > 0.3 ? 'success' : 'failed');
    }, 1500);
  };

  return (
    <Sheet title={`${integration.name} — الإعدادات`} onClose={onClose}>
      <div style={{
        display: 'flex', alignItems: 'center', gap: 16, marginBottom: 24,
        padding: 16, background: T.paper, border: `1px solid ${T.borderLight}`,
      }}>
        <div style={{
          width: 56, height: 56, fontSize: 28,
          background: `${integration.color}15`, color: integration.color,
          display: 'grid', placeItems: 'center',
        }}>
          {integration.logo}
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 16, fontWeight: 700, color: T.ink, marginBottom: 4 }}>{integration.name}</div>
          <div style={{ fontSize: 12, color: T.muted, marginBottom: 8 }}>{integration.desc}</div>
          <StatusBadge status={integration.status} />
        </div>
      </div>

      {/* Mode toggle (for payments) */}
      {integration.mode && (
        <Field label="وضع التشغيل">
          <div style={{ display: 'flex', gap: 8 }}>
            {['sandbox', 'production'].map(m => (
              <button key={m} onClick={() => setMode(m)} style={{
                flex: 1, padding: '10px 14px', fontSize: 12, fontWeight: 700,
                letterSpacing: 0.5,
                background: mode === m ? (m === 'production' ? T.redSoft : T.amberSoft) : T.bg,
                color: mode === m ? (m === 'production' ? T.red : T.amber) : T.muted,
                border: `1px solid ${mode === m ? (m === 'production' ? T.red : T.amber) : T.borderLight}`,
              }}>
                {m === 'production' ? '🔴 Production (Live)' : '🟡 Sandbox (Test)'}
              </button>
            ))}
          </div>
        </Field>
      )}

      {/* Dynamic fields */}
      {integration.fields.map(field => (
        <Field key={field} label={fieldLabels[field] || field}>
          <div style={{ position: 'relative' }}>
            <input
              type={field.includes('password') || field.includes('secret') || field.includes('token') || field.includes('Key') ? 'password' : 'text'}
              value={fields[field] || ''}
              onChange={e => setFields({ ...fields, [field]: e.target.value })}
              placeholder={`أدخل ${fieldLabels[field] || field}...`}
              style={{ ...inputStyle, paddingLeft: 40, fontFamily: 'JetBrains Mono, monospace', fontSize: 12 }}
            />
            <Key size={14} style={{
              position: 'absolute', left: 12, top: '50%',
              transform: 'translateY(-50%)', color: T.faint,
            }} />
          </div>
        </Field>
      ))}

      {/* Webhook URL (read-only, generated) */}
      <Field label="Webhook URL (انسخه وضعه في لوحة المزود)">
        <div style={{ display: 'flex', gap: 8 }}>
          <input
            readOnly
            value={`https://binghaith.com/api/webhook/${integration.id}`}
            style={{
              ...inputStyle, fontFamily: 'JetBrains Mono, monospace',
              fontSize: 11, background: T.paper, color: T.muted,
            }}
          />
          <button onClick={() => navigator.clipboard?.writeText(`https://binghaith.com/api/webhook/${integration.id}`)} style={{
            width: 44, background: T.bg,
            border: `1px solid ${T.borderLight}`, color: T.ink,
            display: 'grid', placeItems: 'center',
          }}>
            <Copy size={14} />
          </button>
        </div>
      </Field>

      {/* Test Connection */}
      <div style={{
        padding: 16, background: T.paper,
        border: `1px solid ${T.borderLight}`, marginBottom: 20,
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: testResult ? 12 : 0 }}>
          <div>
            <div style={{ fontSize: 13, fontWeight: 700, color: T.ink, marginBottom: 2 }}>اختبار الاتصال</div>
            <div style={{ fontSize: 11, color: T.muted }}>يتحقق من صحة المفاتيح</div>
          </div>
          <button onClick={handleTest} disabled={testing} style={{
            padding: '10px 18px',
            background: testing ? T.faint : T.goldUI, color: '#fff',
            fontSize: 12, fontWeight: 700, letterSpacing: 0.5,
            display: 'flex', alignItems: 'center', gap: 6,
            minHeight: 40, cursor: testing ? 'wait' : 'pointer',
          }}>
            {testing ? <RefreshCw size={14} className="spin" /> : <Zap size={14} />}
            {testing ? 'جاري الاختبار...' : 'اختبر الاتصال'}
          </button>
        </div>
        {testResult === 'success' && (
          <div style={{
            display: 'flex', alignItems: 'center', gap: 8,
            padding: 10, background: T.greenSoft, color: T.green,
            fontSize: 12, fontWeight: 600,
          }}>
            <CheckCircle2 size={14} />
            ✓ الاتصال ناجح — جميع المفاتيح صحيحة
          </div>
        )}
        {testResult === 'failed' && (
          <div style={{
            display: 'flex', alignItems: 'center', gap: 8,
            padding: 10, background: T.redSoft, color: T.red,
            fontSize: 12, fontWeight: 600,
          }}>
            <AlertCircle size={14} />
            ✗ فشل الاتصال — تحقق من المفاتيح
          </div>
        )}
      </div>

      <div style={{ display: 'flex', gap: 8, paddingTop: 16, borderTop: `1px solid ${T.borderLight}` }}>
        {integration.status === 'connected' && (
          <button style={{
            flex: 1, padding: '12px',
            border: `1px solid ${T.red}`, color: T.red,
            fontSize: 12, fontWeight: 700, minHeight: 44,
          }}>
            فصل الاتصال
          </button>
        )}
        <button onClick={onClose} style={{
          flex: 1, padding: '12px',
          border: `1px solid ${T.borderLight}`, color: T.ink,
          fontSize: 13, fontWeight: 600, minHeight: 44,
        }}>إلغاء</button>
        <button onClick={onClose} style={{
          flex: 2, padding: '12px',
          background: T.ink, color: '#fff',
          fontSize: 13, fontWeight: 700, letterSpacing: 1, minHeight: 44,
        }}>حفظ الإعدادات</button>
      </div>
    </Sheet>
  );
}

